 1	import * as React from 'react';
 2	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 3	import { SVGIconProps } from '@patternfly/react-icons/dist/js/createIcon';
 4	import { isIstioNamespace } from 'config/ServerConfig';
 5	import { icons } from 'config';
 6	import { KialiIcon } from '../../config/KialiIcon';
 7	import { infoStyle } from 'styles/IconStyle';
 8	
 9	type MissingAuthPolicyProps = {
10	  text?: string;
11	  textTooltip?: string;
12	  tooltip?: boolean;
13	  icon?: React.ComponentClass<SVGIconProps>;
14	  color?: string;
15	  namespace: string;
16	  className?: string;
17	};
18	
19	export const MissingAuthPolicy: React.FC<MissingAuthPolicyProps> = ({
20	  text = 'Missing Authorization Policy',
21	  textTooltip = 'This workload is not covered by any authorization policy.',
22	  tooltip = false,
23	  icon = icons.istio.missingAuthPolicy.icon,
24	  color = icons.istio.missingAuthPolicy.color,
25	  namespace,
26	  className
27	}) => {
28	  const iconComponent = (
29	    <span className={className}>
30	      {React.createElement(icon, { style: { color: color } })}
31	
32	      {!tooltip && (
33	        <span style={{ marginLeft: '0.5rem' }}>
34	          {text}
35	
36	          <Tooltip
37	            key="tooltip_missing_auth_policy"
38	            position={TooltipPosition.top}
39	            content={<div style={{ textAlign: 'left' }}>{textTooltip}</div>}
40	          >
41	            <KialiIcon.Info className={infoStyle} />
42	          </Tooltip>
43	        </span>
44	      )}
45	    </span>
46	  );
47	
48	  if (isIstioNamespace(namespace)) {
49	    return <></>;
50	  }
51	
52	  return tooltip ? (
53	    <Tooltip content={<div style={{ textAlign: 'left' }}>{textTooltip}</div>} position={TooltipPosition.right}>
54	      {iconComponent}
55	    </Tooltip>
56	  ) : (
57	    iconComponent
58	  );
59	};

